INSERT INTO `gsbpms` VALUES
(1,1,'Identifikasi Kebutuhan (Specify Needs)','1.1. Identifikasi Kebutuhan\r\n1.2. Konsultasi dan Konfirmasi\r\n1.3. Menentukan Tujuan\r\n1.4. Mengidentikasi Konsep dan Definisi\r\n1.5. Memeriksa Ketersediaan Data\r\n1.6. Membuat Proposal Kegiatan\r\n',NULL,NULL),
(2,2,'Perancangan (Design)','2.1. Merancang Output\r\n2.2. Merancang Deskripsi Variabel\r\n2.3. Merancang Pengumpulan data\r\n2.4. Merancang Kerangka Sampel dan Pengambilan Sampel\r\n2.5. Mendesain Sampling\r\n2.6. Merancang Pengolahan dan Analisis\r\n2.7. Merancang Sistem Alur Kerja\r\n',NULL,NULL),
(3,3,'Implementasi Rancangan (Build)','3.1. Menyusun Instrumen Pengumpulan data\r\n3.2. Menyusun Komponen Pengolahan dan Analasis\r\n3.3. Menyusun Komponen Diseminasi\r\n3.4. Menyusun Alur Kerja \r\n3.5. Uji Coba Pelaksanaan\r\n',NULL,NULL),
(4,4,'Pengumpulan Data (Collect)','4.1. Merancang Kerangka Sampel\r\n4.2. Menentukan Pengambilan sampel\r\n4.3. Melakukan Pelatihan Petugas\r\n4.4. Melakukan Pengumpulan data\r\n',NULL,NULL),
(5,5,'Pengolahan Data (Processing)','5.1. Integrasi Data\r\n5.2. Pengklasifikasian dan Pengkodean\r\n5.3. Review dan validasi\r\n5.4. Penyuntingan dan Imputasi\r\n5.5. Memperoleh variable dan unit baru\r\n5.6. Penghitungan Penimbang \r\n5.7. Pengihtungan Populasi\r\n5.8. Finalisasi data\r\n',NULL,NULL),
(6,6,'Analisis (Analyze)','6.1. Menyiapkan Naskah Output\r\n6.2. Validasi Outout\r\n6.3. Interpretasi Output\r\n6.4. Kebijakan Penyajian data\r\n',NULL,NULL),
(7,7,'Diseminasi (Dissemination)','7.1. Sinkronisasi antara data dengan metadata\r\n7.2. Menghasilkan Produk Diseminasi\r\n7.3. Manajemen Produk diseminasi\r\n7.4. Mempromosikan produk diseminasi\r\n7.5. Manajemen user support\r\n',NULL,NULL),
(8,8,'Evaluasi (Evaluation)','8.1. Mengumpulkan masukan evaluasi\r\n8.2. Evaluasi Hasil\r\n',NULL,NULL);
INSERT INTO `indikators` VALUES
(1,'Bersikap adil dan tidak membeda-bedakan para pemangku kepentingan',1,'2022-07-31 23:41:17','2022-07-31 23:41:17'),
(2,'Memberikan layanan sesuai SOP',1,'2022-07-31 23:49:02','2022-07-31 23:49:02'),
(3,'Mengevaluasi, memperbaiki dan meningkatkan kualitas layanan yang diberikan dari waktu ke waktu ',1,'2022-07-31 23:49:38','2022-07-31 23:49:38'),
(4,'Proaktif dan responsif menindaklanjuti keluhan/kebutuhan pelanggan',2,'2022-07-31 23:50:30','2022-07-31 23:50:30'),
(5,'Segera mencari jalan keluar saat menemukan kendala / permasalahan dalam memberikan pelayanan',2,'2022-07-31 23:50:40','2022-07-31 23:50:40'),
(6,'Aktif meningkatkan kompetensi diri serta menunjukkan inisiatif untuk memberikan pengetahuan dan keterampilan yang dimiliki',3,'2022-07-31 23:50:55','2022-07-31 23:50:55'),
(7,'Mengoptimalkan kompetensi yang dimiliki untuk menyelesaikan tugas dan tanggung jawab.',3,'2022-07-31 23:53:13','2022-07-31 23:53:13'),
(8,'Melakukan pekerjaan dengan berfokus pada dampak bukan hanya hasil serta mampu melakukan identifikasi mitigasi risiko',3,'2022-07-31 23:53:47','2022-07-31 23:53:47'),
(9,'Bekerja dengan perencanaan matang dan tuntas dengan hasil kualitas terbaik dan berani mempertanggungjawabkan pekerjaannya.',4,'2022-07-31 23:54:08','2022-07-31 23:54:08'),
(10,'Menunjukkan antusiasme dan semangat bekerja yang tinggi.',4,'2022-07-31 23:54:21','2022-07-31 23:54:21'),
(11,'Menunjukkan perilaku kooperatif terhadap anggota tim atau unit kerja lain tanpa membedakan latar belakang',5,'2022-07-31 23:54:45','2022-07-31 23:54:45'),
(12,'Mengutamakan kolaborasi untuk mencapai hasil kerja terbaik.',5,'2022-07-31 23:55:05','2022-07-31 23:55:05'),
(13,'Bersikap transparan, terbuka serta memberikan dukungan moral dan semangat terhadap anggota tim',5,'2022-07-31 23:55:16','2022-07-31 23:55:16'),
(14,'Melakukan identifikasi permasalahan untuk memberikan solusi terbaik.',6,'2022-07-31 23:55:32','2022-07-31 23:55:32'),
(15,'Menjaga komitmen terhadap keputusan bersama dalam kelompok',6,'2022-07-31 23:55:40','2022-07-31 23:55:40'),
(16,'Membantu dengan memberikan bimbingan kepada rekan maupun bawahan yang terlihat mengalami kesulitan saat bekerja',7,'2022-07-31 23:56:15','2022-07-31 23:56:15'),
(17,'Menciptakan situasi yang mendorong untuk mengembangkan organisasi serta kemampuan belajar secara berkelanjutan',7,'2022-08-15 19:19:20','2022-08-15 19:19:20'),
(18,'Menciptakan situasi yang mendorong anggota tim untuk belajar menjadi pemimpin (kaderisasi)',7,'2022-08-15 19:19:26','2022-08-15 19:19:26'),
(19,'Menggunakan metode komunikasi yang tepat untuk memastikan penjelasan atau arahan yang diberikan dapat dipahami dengan baik',8,'2022-08-15 19:19:33','2022-08-15 19:19:33'),
(20,'Menampilkan perilaku positif selama bekerja sehingga dapat menjadi panutan',8,'2022-08-15 19:19:45','2022-08-15 19:19:45'),
(21,'Mereview atau mengevaluasi hasil kerja dalam rangka memastikan kualitas pekerjaan dan perbaikan',9,'2022-08-15 19:19:54','2022-08-15 19:19:54'),
(22,'Terbuka terhadap informasi atau pengetahuan baru/up to date',9,'2022-08-15 19:20:00','2022-08-15 19:20:00'),
(23,'Pelaksanaan dan implementasi rencana perubahan',9,'2022-08-15 19:20:05','2022-08-15 19:20:05'),
(24,'Mengimplementasikan cara-cara baru untuk mempermudah pekerjaan guna menghasilkan kinerja yang lebih baik',10,'2022-08-15 19:20:15','2022-08-15 19:20:15'),
(25,'Mencari ide dan menyusun rencana yang matang untuk mewujudkan ide.',10,'2022-08-15 19:20:27','2022-08-15 19:20:27'),
(26,'Berpikir, berbicara dan berbuat kebenaran meskipun tidak populer/umum',11,'2022-08-15 19:20:40','2022-08-15 19:20:40'),
(27,'Amanah dan bertindak sesuai aturan meskipun tidak diawasi ',11,'2022-08-15 19:20:46','2022-08-15 19:20:46'),
(28,'Konsisten antara perkataan dan perbuatan yang selaras dengan prinsip-prinsip moral',12,'2022-08-15 19:20:53','2022-08-15 19:20:53'),
(29,'Menjaga nama baik Institusi di berbagai situasi',12,'2022-08-15 19:21:01','2022-08-15 19:21:01'),
(30,'Menjunjung tinggi kode etik dan profesi yang berlaku di lingkungan Institusi',12,'2022-08-15 19:21:06','2022-08-15 19:21:06'),
(31,'Melaksanakan tugas kedinasan dengan penuh pengabdian, kesadaran, dan tanggung jawab',13,'2022-08-15 19:21:12','2022-08-15 19:21:12'),
(32,'Selalu menaati aturan kedinasan',13,'2022-08-15 19:21:19','2022-08-15 19:21:19'),
(33,'Berpartisipasi aktif dan konsisten dalam penentuan target serta langkah pencapaian target kinerja',14,'2022-08-15 19:21:33','2022-08-15 19:21:33'),
(34,'Berani mengingatkan kepada pegawai lain dalam rangka penerapan aturan serta pencapaian target kinerja',14,'2022-08-15 19:21:38','2022-08-15 19:21:38'),
(35,'Berpartisipasi aktif dalam agenda kedinasan (apel, meeting, gathering, forum lain)',14,'2022-08-15 19:21:43','2022-08-15 19:21:43');
