INSERT INTO `interpretasis` VALUES
(3,5,'Jumlah penduduk yang memiliki rata-rata pengeluaran perkapita perbulan di bawah garis kemiskinan',1,'2022-08-29 09:36:00','2022-08-29 09:36:00'),
(4,6,'Persentase penduduk yang berada dibawah Garis Kemiskinan (GK).',1,'2022-08-29 09:36:26','2022-08-29 09:36:26'),
(5,7,'Indeks Kedalaman Kemiskinan (Poverty Gap Index-P1), merupakan ukuran rata-rata kesenjangan pengeluaran masing-masing penduduk miskin terhadap garis kemiskinan. Semakin tinggi nilai indeks, semakin jauh rata-rata pengeluaran pesuduk dari garis kemiskinan.',1,'2022-08-29 09:36:44','2022-08-29 09:36:44'),
(6,8,'Indeks Keparahan Kemiskinan (Proverty Severity Index-P2) memberikan gambaran mengenai penyebaran pengeluaran diantara penduduk miskin. Semakin tinggi nilai indeks, semakin tinggi ketimpangan pengeluaran diantara penduduk miskin.',1,'2022-08-29 09:37:02','2022-08-29 09:37:02'),
(8,34,'Suatu nilai yang menunjukkan rata-rata hasil produksi per satuan luas per komoditas padi pada periode satu tahun laporan.',1,'2022-08-29 09:53:48','2022-08-29 09:53:48'),
(9,38,'Output/nilai tambah dari barang dan jasa di suatu wilayah dalam waktu tertentu yang dihitung menggunakan harga yang berlaku pada tahun berjalan\n',1,'2022-08-29 09:54:16','2022-08-29 09:54:16'),
(10,40,'Indikator ini menunjukkan apakah perempuan dapat memainkan peranan aktif dalam kehidupan ekonomi dan politik.\n',1,'2022-08-29 09:54:49','2022-08-29 09:54:49'),
(11,19,'TPT (Tingkat Pengangguran Terbuka) adalah persentase jumlah pengangguran terhadap jumlah angkatan kerja.',1,'2022-08-29 10:07:28','2022-08-29 10:07:28'),
(12,20,'Persentase penduduk usia 15 tahun keatas yang merupakan angkatan kerja.\nSemakin tinggi TPAK menunjukkan bahwa semakin tinggi pula pasokan tenaga kerja (labour supply) yang tersedia untuk memproduksi barang dan jasa dalam suatu perekonomian.',1,'2022-08-29 10:07:51','2022-08-29 10:07:51'),
(13,22,'Jumlah penduduk yang melakukan kegiatan/pekerjaan paling sedikit satu jam berturut-turut selama satu minggu yang lalu dengan maksud untuk memperoleh pendapatan dan keuntungan.',1,'2022-08-29 10:08:13','2022-08-29 10:08:13'),
(14,23,'Jumlah penduduk yang melakukan kegiatan/pekerjaan paling sedikit satu jam berturut-turut selama satu minggu yang lalu dengan maksud untuk memperoleh pendapatan dan keuntungan di Lapangan Usaha Pertanian\n',1,'2022-08-29 10:08:26','2022-08-29 10:08:26'),
(15,24,'Jumlah penduduk yang melakukan kegiatan/pekerjaan paling sedikit satu jam berturut-turut selama satu minggu yang lalu dengan maksud untuk memperoleh pendapatan dan keuntungan di Lapangan Usaha Manufaktur\n',1,'2022-08-29 10:08:38','2022-08-29 10:08:38'),
(16,25,'Jumlah penduduk yang melakukan kegiatan/pekerjaan paling sedikit satu jam berturut-turut selama satu minggu yang lalu dengan maksud untuk memperoleh pendapatan dan keuntungan di Lapangan Usaha Jasa\n',1,'2022-08-29 10:08:55','2022-08-29 10:08:55'),
(17,28,'Pekerja sektor formal merupakan status pekerjaan utama seseotang yang mencakup berusaha berusaha dibantu buruh tetap/dibayar dan buruh/karyawan/pegawai\n',1,'2022-08-29 10:09:13','2022-08-29 10:09:13'),
(18,9,'Garis Kemiskinan (GK) merupakan penjumlahan dari Garis Kemiskinan Makanan (GKM) dan Garis Kemiskinan Non Makanan (GKNM). Garis Kemiskinan Makanan (GKM) merupakan nilai pengeluaran kebutuhan minimum makanan yang disetarakan dengan 2100 kilokalori perkapita perhari. Paket komoditi kebutuhan dasar makanan diwakili oleh 52 jenis komoditi (padi-padian, umbi-umbian, ikan, daging, telur dan susu, sayuran, kacang-kacangan, buah-buahan, minyak dan lemak, dll). Garis Kemiskinan Non Makanan (GKNM) adalah kebutuhan minimum untuk perumahan, sandang, pendidikan dan kesehatan. Paket komoditi kebutuhan dasar non makanan diwakili oleh 51 jenis komoditi di perkotaan dan 47 jenis komoditi di pedesaan.\n',1,'2022-08-30 03:25:38','2022-08-30 03:25:38'),
(19,10,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah (tanpa memandang jenjang pendidikan yang ditempuhi) terhadap penduduk kelompok usia sekolah yang bersesuaian. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APS berkisar antara 0-100. Makin tinggi APS berarti makin banyak anak usia sekolah yang bersekolah di suatu daerah. APS yang tinggi menunjukkan terbukanya peluang yang lebih besar dalam mengakses pendidikan secara umum. Pada kelompok kelompok umur mana peluang tersebut terjadi dapat dilihat dari besarnya APS pada setiap kelompok umur. Contoh: APS 7-12 tahun Kabupaten Boalemo Tahun 2017 sebesar 98,85 persen, artinya sekitar 99 persen penduduk berusia 7-12 tahun di Kabupaten Boalemo sedang bersekolah',1,'2022-08-31 01:40:51','2022-08-31 01:40:51'),
(20,11,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah (tanpa memandang jenjang pendidikan yang ditempuhi) terhadap penduduk kelompok usia sekolah yang bersesuaian. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APS berkisar antara 0-100. Makin tinggi APS berarti makin banyak anak usia sekolah yang bersekolah di suatu daerah. APS yang tinggi menunjukkan terbukanya peluang yang lebih besar dalam mengakses pendidikan secara umum. Pada kelompok kelompok umur mana peluang tersebut terjadi dapat dilihat dari besarnya APS pada setiap kelompok umur. Contoh: APS 13-15 tahun Kabupaten Boalemo Tahun 2017 sebesar 88,39 persen, artinya sekitar 88 persen penduduk berusia 13-15 tahun di Kabupaten Boalemo sedang bersekolah',1,'2022-08-31 01:42:02','2022-08-31 01:42:02'),
(21,12,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah (tanpa memandang jenjang pendidikan yang ditempuhi) terhadap penduduk kelompok usia sekolah yang bersesuaian. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APS berkisar antara 0-100. Makin tinggi APS berarti makin banyak anak usia sekolah yang bersekolah di suatu daerah. APS yang tinggi menunjukkan terbukanya peluang yang lebih besar dalam mengakses pendidikan secara umum. Pada kelompok kelompok umur mana peluang tersebut terjadi dapat dilihat dari besarnya APS pada setiap kelompok umur. Contoh: APS 16-18 tahun Kabupaten Boalemo Tahun 2017 sebesar 69,89 persen, artinya sekitar 70 persen penduduk berusia 16-18 tahun di Kabupaten Boalemo sedang bersekolah',1,'2022-08-31 01:42:52','2022-08-31 01:42:52'),
(22,21,'Jumlah Pengangguran adalah jumlah mereka yang tak punya pekerjaan dan (mencari pekerjaan atau mempersiapkan usaha), mereka yang tak punya pekerjaan dan tidak mencari pekerjaan, karena merasa tidak mungkin mendapatkan pekerjaan, dan mereka yang sudah punya pekerjaan, tetapi belum mulai bekerja.',1,'2022-08-31 02:02:01','2022-08-31 02:02:01'),
(23,26,'Pekerja setengah pengangguran adalah mereka yang bekerja di bawah jam kerja normal (kurang dari 35 jam seminggu) dan masih mencari pekerjaan atau masih bersedia menerima pekerjaan (dahulu disebut setengah pengangguran terpaksa).\n\nMenggambarkan kemampuan ekonomi untuk menyediakan lapangan kerja yang mampu memanfaatkan keahlian, pengalaman  dan kesediaan bekerja yang dimiliki tenaga  kerjanya. Tingkat setengah pengangguran dapat memberikan gambaran tentang kualitas, produktivitas, dan tingkat utilisasi lapangan kerja yang tersedia, terutama di negara-negara dengan tingkat pengangguran terbuka rendah.',1,'2022-08-31 02:40:42','2022-08-31 02:40:42'),
(24,27,'Pekerja setengah pengangguran adalah mereka yang bekerja di bawah jam kerja normal (kurang dari 35 jam seminggu) dan masih mencari pekerjaan atau masih bersedia menerima pekerjaan (dahulu disebut setengah pengangguran terpaksa).\n\nMenggambarkan kemampuan ekonomi untuk menyediakan lapangan kerja yang mampu memanfaatkan keahlian, pengalaman  dan kesediaan bekerja yang dimiliki tenaga  kerjanya. Tingkat setengah pengangguran dapat memberikan gambaran tentang kualitas, produktivitas, dan tingkat utilisasi lapangan kerja yang tersedia, terutama di negara-negara dengan tingkat pengangguran terbuka rendah.',1,'2022-08-31 02:45:56','2022-08-31 02:45:56'),
(25,29,'Pekerja sektor informal merupakan status pekerjaan utama seseotang yang mencakup berusaha sendiri, berusaha dibantu buruh tidak tetap, berusaha dibantu buruh tetap, buruh/karyawan, pekerja bebas di pertanian, pekerja bebas di nonpertanian dan pekerja keluarga/tidak dibayar.',1,'2022-08-31 03:14:46','2022-08-31 03:14:46'),
(26,35,'IPM menjelaskan bagaimana penduduk dapat mengakses hasil pembangunan dalam memperoleh pendapatan, kesehatan, pendidikan, dan sebagainya. IPM merupakan indikator penting untuk mengukur keberhasilan dalam upaya membangun kualitas hidup manusia (masyarakat/penduduk). Bagi Indonesia, IPM merupakan data strategis karena selain sebagai ukuran kinerja Pemerintah, IPM juga digunakan sebagai salah satu alokator penentuan Dana Alokasi Umum (DAU).',1,'2022-08-31 03:17:24','2022-08-31 03:17:24'),
(27,36,'Pertumbuhan ekonomi merupakan salah satu indikator makro untuk melihat kinerja perekonomian secara riil di suatu wilayah. Laju pertumbuhan ekonomi dihitung berdasarkan perubahan PDRB atas dasar harga konstan tahun yang bersangkutan terhadap tahun sebelumnya. Pertumbuhan ekonomi dapat dipandang sebagai pertambahan jumlah barang dan jasa yang dihasilkan oleh semua lapangan usaha kegiatan ekonomi yang ada di suatu wilayah selama kurun waktu setahun. ',1,'2022-08-31 03:17:49','2022-08-31 03:17:49'),
(28,37,'Output/nilai tambah dari barang dan jasa di suatu wilayah dalam waktu tertentu yang dihitung menggunakan harga pada tahun tertentu sebagai tahun dasar. Tahun Dasar adalah tahun terpilih sebagai referensi statistik, yang digunakan sebagai dasar penghitungan tahun-tahun yang lain. Tahun dasar yang digunakan saat ini adalah tahun 2010.',1,'2022-08-31 03:38:51','2022-08-31 03:38:51'),
(30,39,'Indeks Pembangunan Gender (IPG) merupakan ukuran pembangunan manusia yang merupakan komposit dari empat indikator, yang lebih menekankan status perempuan, khususnya dalam mengukur kemampuan dasar. IPG mengungkapkan ketidakadilan pencapaian laki-laki dan perempuan. Semakin kecil jarak IPG dengan nilai 100, maka semakin setara pembangunan antara laki-laki dengan perempuan.',1,'2022-08-31 06:46:02','2022-08-31 06:46:02'),
(32,30,'IKK adalah suatu indeks yang menggambarkan tingkat perbandingan harga barang konstruksi antar wilayah. Sesuai dengan pengertiannya IKK dapat dikategorikan sebagai indeks spasial, yaitu indeks yang menggambarkan perbandingan harga untuk lokasi yang berbeda pada periode waktu tertentu.',1,'2022-08-31 06:47:06','2022-08-31 06:47:06'),
(33,31,'Jumlah jasa akomodasi mencakup usaha akomodasi berbintang maupun non bintang.',1,'2022-08-31 06:48:10','2022-08-31 06:48:10'),
(34,32,'Hasil perkalian antara luas panen dengan produktivitas (hasil per hektar).  Indikator ini bergunan untuk menyediakan informasi yang akurat dan terkini bagi kebutuhan pemerintah dan masyarakat umum. Dengan tersedianya data produksi padi dan palawija secara berkesinambungan setiap tahun diharapkan dapat digunakan untuk bahan perencanaan/perumusan kebijakan berkaitan dengan ketahanan pangan nasional, sekaligus sebagi bahan untuk melakukan evaluasi terhadap hasil-hasil pembangunan sektor pertanian khususnya subsektor tanaman pangan.',1,'2022-08-31 06:49:44','2022-08-31 06:49:44'),
(35,33,'Luas tanaman yang dipungut hasilnya setelah tanaman tersebut cukup umur dan hasilnya paling sedikit 11% dari keadaan normal. Indikator ini bergunan untuk mengetahui luas tanaman padi untuk digunakan dalam pengambilan kebijakan oleh pemerintah di sektor pertanian khususnya tanaman pangan.',1,'2022-08-31 06:50:16','2022-08-31 06:50:16'),
(37,13,'Perbandingan antara jumlah penduduk yang masih bersekolah di jenjang pendidikan tertentu (tanpa memandang usia penduduk tersebut) dengan jumlah penduduk yang memenuhi syarat resmi penduduk usia sekolah di jenjang pendidikan yang sama. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APK bisa lebih dari 100 persen karena populasi murid yang bersekolah pada suatu jenjang pendidikan tertentu mencakup anak di luar batas usia sekolah pada jenjang pendidikan tersebut. Penyebabnya adalah adanya pendaftaran siswa usia dini, pendaftaran siswa yang telat bersekolah, atau pengulangan kelas. Hal ini juga dapat menunjukkan bahwa wilayah tersebut mampu menampung penduduk usia sekolah lebih dari target yang sesungguhnya. APK yang tinggi menunjukkan tingginya tingkat partisipasi sekolah, tanpa memperhatikan ketepatan usia sekolah pada jenjang pendidikannya. Contoh: APK SD Kabupaten Boalemo Tahun 2017 sebesar 110,24 persen, artinya persentase penduduk berusia 7-12 tahun di Kabupaten Boalemo yang bersekolah di tingkat SD sekitar 110 persen.',1,'2022-08-31 07:23:56','2022-08-31 07:23:56'),
(38,14,'Perbandingan antara jumlah penduduk yang masih bersekolah di jenjang pendidikan tertentu (tanpa memandang usia penduduk tersebut) dengan jumlah penduduk yang memenuhi syarat resmi penduduk usia sekolah di jenjang pendidikan yang sama. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APK bisa lebih dari 100 persen karena populasi murid yang bersekolah pada suatu jenjang pendidikan tertentu mencakup anak di luar batas usia sekolah pada jenjang pendidikan tersebut. Penyebabnya adalah adanya pendaftaran siswa usia dini, pendaftaran siswa yang telat bersekolah, atau pengulangan kelas. Hal ini juga dapat menunjukkan bahwa wilayah tersebut mampu menampung penduduk usia sekolah lebih dari target yang sesungguhnya. APK yang tinggi menunjukkan tingginya tingkat partisipasi sekolah, tanpa memperhatikan ketepatan usia sekolah pada jenjang pendidikannya. Contoh: APK SMP Kabupaten Boalemo Tahun 2017 sebesar 81,15 persen, artinya persentase penduduk berusia 13-15 tahun di Kabupaten Boalemo yang bersekolah di tingkat SD sekitar 81 persen.',1,'2022-08-31 07:24:43','2022-08-31 07:24:43'),
(39,15,'Perbandingan antara jumlah penduduk yang masih bersekolah di jenjang pendidikan tertentu (tanpa memandang usia penduduk tersebut) dengan jumlah penduduk yang memenuhi syarat resmi penduduk usia sekolah di jenjang pendidikan yang sama. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, dan Paket C) turut diperhitungkan.\n\nNilai APK bisa lebih dari 100 persen karena populasi murid yang bersekolah pada suatu jenjang pendidikan tertentu mencakup anak di luar batas usia sekolah pada jenjang pendidikan tersebut. Penyebabnya adalah adanya pendaftaran siswa usia dini, pendaftaran siswa yang telat bersekolah, atau pengulangan kelas. Hal ini juga dapat menunjukkan bahwa wilayah tersebut mampu menampung penduduk usia sekolah lebih dari target yang sesungguhnya. APK yang tinggi menunjukkan tingginya tingkat partisipasi sekolah, tanpa memperhatikan ketepatan usia sekolah pada jenjang pendidikannya. Contoh: APK SMA Kabupaten Boalemo Tahun 2017 sebesar 70,83 persen, artinya persentase penduduk berusia 16-18 tahun di Kabupaten Boalemo yang bersekolah di tingkat SMA sekitar 71 persen.',1,'2022-08-31 07:25:23','2022-08-31 07:25:23'),
(40,16,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah tepat di jenjang pendidikan yang seharusnya (sesuai antara umur penduduk dengan ketentuan usia bersekolah di jenjang tersebut) terhadap penduduk kelompok usia sekolah yang bersesuain. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, Paket C) turut diperhitungkan.\n\nNilai APM berkisar antara 0-100. APM menunjukkan seberapa banyak penduduk usia sekolah yang sudah dapat memanfaatkan fasilitas pendidikan sesuai pada jenjang pendidikannya. Bila seluruh anak usia sekolah dapat bersekolah tepat waktu, maka APM akan mencapai 100 persen. Secara umum, APM akan selalu lebih rendah dari APK karena APK memperhitungkan jumlah penduduk di luar usia sekolah pada jenjang pendidikan yang bersangkutan Contoh: APM SD Kabupaten Boalemo Tahun 2017 sebesar 97,71 persen, artinya sekitar 98 persen penduduk di Kabupaten Boalemo yang berusia 7-12 tahun bersekolah tepat waktu dijenjang SD/sederajat.',1,'2022-08-31 07:27:48','2022-08-31 07:27:48'),
(41,17,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah tepat di jenjang pendidikan yang seharusnya (sesuai antara umur penduduk dengan ketentuan usia bersekolah di jenjang tersebut) terhadap penduduk kelompok usia sekolah yang bersesuain. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, Paket C) turut diperhitungkan.\n\nNilai APM berkisar antara 0-100. APM menunjukkan seberapa banyak penduduk usia sekolah yang sudah dapat memanfaatkan fasilitas pendidikan sesuai pada jenjang pendidikannya. Bila seluruh anak usia sekolah dapat bersekolah tepat waktu, maka APM akan mencapai 100 persen. Secara umum, APM akan selalu lebih rendah dari APK karena APK memperhitungkan jumlah penduduk di luar usia sekolah pada jenjang pendidikan yang bersangkutan Contoh: APM SMP Kabupaten Boalemo Tahun 2017 sebesar 64,7 persen, artinya sekitar 65 persen penduduk di Kabupaten Boalemo yang berusia 13-15 tahun bersekolah tepat waktu dijenjang SMP/sederajat.',1,'2022-08-31 07:28:44','2022-08-31 07:28:44'),
(42,18,'Proporsi dari penduduk kelompok usia sekolah tertentu yang sedang bersekolah tepat di jenjang pendidikan yang seharusnya (sesuai antara umur penduduk dengan ketentuan usia bersekolah di jenjang tersebut) terhadap penduduk kelompok usia sekolah yang bersesuain. Sejak tahun 2007, Pendidikan Non Formal (Paket A, Paket B, Paket C) turut diperhitungkan.\n\nNilai APM berkisar antara 0-100. APM menunjukkan seberapa banyak penduduk usia sekolah yang sudah dapat memanfaatkan fasilitas pendidikan sesuai pada jenjang pendidikannya. Bila seluruh anak usia sekolah dapat bersekolah tepat waktu, maka APM akan mencapai 100 persen. Secara umum, APM akan selalu lebih rendah dari APK karena APK memperhitungkan jumlah penduduk di luar usia sekolah pada jenjang pendidikan yang bersangkutan Contoh: APM SMA Kabupaten Boalemo Tahun 2017 sebesar 52,31 persen, artinya sekitar 52 persen penduduk di Kabupaten Boalemo yang berusia 16-18 tahun bersekolah tepat waktu dijenjang SMA/sederajat.',1,'2022-08-31 07:29:45','2022-08-31 07:29:45');
